//! EngineContract.g.cs emitter — radiates the contract to C# (ADR-0018).
//!
//! Every value is read from the compiled contract items themselves
//! (`offset_of!`/`size_of!` on the real `#[repr(C)]` types, the actual
//! consts), so the generated numbers cannot drift from the Rust truth.
//! The output is committed; `tests/drift.rs` runs `--check` inside
//! `cargo test --workspace`, so an out-of-date generated file fails the
//! ordinary test gate.
//!
//! Usage: `just contract-gen` (write) / `gen-contract --check` (verify).

use std::mem::{offset_of, size_of};
use std::path::PathBuf;

use fmf_contract::pod::{
    FmfBlob, FmfEvent, FmfPage, FmfQueryOptions, FmfRow, FmfVolumeStatus, FrameHeader,
};
use fmf_contract::{codes, counters, limits, opcodes, versions};

fn pascal(snake: &str) -> String {
    snake
        .split('_')
        .map(|w| {
            let mut c = w.chars();
            match c.next() {
                Some(f) => f.to_uppercase().collect::<String>() + c.as_str(),
                None => String::new(),
            }
        })
        .collect()
}

fn render() -> String {
    let mut o = String::new();
    let mut w = |line: &str| {
        o.push_str(line);
        o.push_str("\r\n");
    };

    w("// <auto-generated>");
    w("//   Generated by fmf-contract's gen-contract from the canonical contract");
    w("//   definitions (engine/crates/fmf-contract — ADR-0018). DO NOT EDIT:");
    w("//   regenerate with `just contract-gen`; `cargo test --workspace` fails");
    w("//   on drift. Field offsets are the offset_of! values of the compiled");
    w("//   Rust #[repr(C)] types — no hand-derived numbers exist on this side.");
    w("// </auto-generated>");
    w("");
    w("using System.Runtime.InteropServices;");
    w("");
    w("namespace FindMyFiles.Engine;");
    w("");
    w("/// <summary>The engine contract, radiated from fmf-contract.</summary>");
    w("internal static class EngineContract");
    w("{");
    w(&format!(
        "    public const uint AbiVersion = {};",
        versions::ABI_VERSION
    ));
    w(&format!(
        "    public const uint ProtocolVersion = {};",
        versions::PROTOCOL_VERSION
    ));
    w("");
    w("    /// <summary>Pipe name without the <c>\\\\.\\pipe\\</c> prefix.</summary>");
    w(&format!(
        "    public const string PipeNameShort = \"{}\";",
        versions::PIPE_NAME_SHORT
    ));
    w("");
    w("    /// <summary>Status codes (frame header / FFI returns). Append-only.</summary>");
    w("    public static class Status");
    w("    {");
    for (name, v) in [
        ("Ok", codes::OK),
        ("InvalidArg", codes::INVALID_ARG),
        ("Stale", codes::STALE),
        ("NotAdmin", codes::NOT_ADMIN),
        ("Volume", codes::VOLUME),
        ("QuerySyntax", codes::QUERY_SYNTAX),
        ("Io", codes::IO),
        ("Locked", codes::LOCKED),
        ("Panic", codes::PANIC),
    ] {
        w(&format!("        public const int {name} = {v};"));
    }
    w("    }");
    w("");
    w("    /// <summary>Pipe opcodes. Event pushes reuse 1..6 as the kind with");
    w("    /// the event flag set — branch on the flag before the opcode.</summary>");
    w("    public static class Op");
    w("    {");
    for (name, v) in [
        ("Hello", opcodes::HELLO),
        ("Subscribe", opcodes::SUBSCRIBE),
        ("Unsubscribe", opcodes::UNSUBSCRIBE),
        ("ListVolumes", opcodes::LIST_VOLUMES),
        ("IndexStart", opcodes::INDEX_START),
        ("IndexStatus", opcodes::INDEX_STATUS),
        ("Query", opcodes::QUERY),
        ("ResultPage", opcodes::RESULT_PAGE),
        ("ResultFree", opcodes::RESULT_FREE),
        ("Stats", opcodes::STATS),
        ("FlushReserved", opcodes::FLUSH_RESERVED),
        ("ServiceInfo", opcodes::SERVICE_INFO),
    ] {
        w(&format!("        public const ushort {name} = {v};"));
    }
    w("    }");
    w("");
    w("    // ── Limits ──────────────────────────────────────────────────────");
    w(&format!(
        "    public const uint MaxPayloadLen = {};",
        limits::MAX_PAYLOAD_LEN
    ));
    w(&format!(
        "    public const int MaxResultsPerConn = {};",
        limits::MAX_RESULTS_PER_CONN
    ));
    w(&format!(
        "    public const int EventQueueCap = {};",
        limits::EVENT_QUEUE_CAP
    ));
    w(&format!(
        "    public const int PageRows = {};",
        limits::PAGE_ROWS
    ));
    w("");
    w("    // ── POD layouts (offset_of! truth) ──────────────────────────────");
    w(&format!(
        "    public const int FrameHeaderLen = {};",
        size_of::<FrameHeader>()
    ));
    w("    public static class FrameOffsets");
    w("    {");
    w(&format!(
        "        public const int Len = {};",
        offset_of!(FrameHeader, len)
    ));
    w(&format!(
        "        public const int Opcode = {};",
        offset_of!(FrameHeader, opcode)
    ));
    w(&format!(
        "        public const int Flags = {};",
        offset_of!(FrameHeader, flags)
    ));
    w(&format!(
        "        public const int RequestId = {};",
        offset_of!(FrameHeader, request_id)
    ));
    w(&format!(
        "        public const int Status = {};",
        offset_of!(FrameHeader, status)
    ));
    w("    }");
    w("");
    w(&format!(
        "    public const int RowSize = {};",
        size_of::<FmfRow>()
    ));
    w("    public static class RowOffsets");
    w("    {");
    w(&format!(
        "        public const int EntryRef = {};",
        offset_of!(FmfRow, entry_ref)
    ));
    w(&format!(
        "        public const int Frn = {};",
        offset_of!(FmfRow, frn)
    ));
    w(&format!(
        "        public const int Size = {};",
        offset_of!(FmfRow, size)
    ));
    w(&format!(
        "        public const int Mtime = {};",
        offset_of!(FmfRow, mtime)
    ));
    w(&format!(
        "        public const int NameOff = {};",
        offset_of!(FmfRow, name_off)
    ));
    w(&format!(
        "        public const int ParentPathOff = {};",
        offset_of!(FmfRow, parent_path_off)
    ));
    w(&format!(
        "        public const int Flags = {};",
        offset_of!(FmfRow, flags)
    ));
    w(&format!(
        "        public const int NameLen = {};",
        offset_of!(FmfRow, name_len)
    ));
    w(&format!(
        "        public const int ParentPathLen = {};",
        offset_of!(FmfRow, parent_path_len)
    ));
    w("    }");
    w("");
    w(&format!(
        "    public const int EventSize = {};",
        size_of::<FmfEvent>()
    ));
    w(&format!(
        "    public const int QueryOptionsSize = {};",
        size_of::<FmfQueryOptions>()
    ));
    w(&format!(
        "    public const int VolumeStatusSize = {};",
        size_of::<FmfVolumeStatus>()
    ));
    w(&format!(
        "    public const int PageStructSize = {};",
        size_of::<FmfPage>()
    ));
    w(&format!(
        "    public const int BlobSize = {};",
        size_of::<FmfBlob>()
    ));
    w("}");
    w("");
    w("/// <summary>Event kinds — FFI FmfEvent.Kind and pipe event-push opcodes");
    w("/// carry the same values. EngineError rides severity in Entries");
    w("/// (1=warn 2=error 3=panic).</summary>");
    w("internal enum EventKind : uint");
    w("{");
    w("    Progress = 1,");
    w("    VolumeReady = 2,");
    w("    IndexChanged = 3,");
    w("    RescanStarted = 4,");
    w("    VolumeFailed = 5,");
    w("    EngineError = 6,");
    w("}");
    w("");
    w("/// <summary>Degradation counters of the stats JSON (snake_case keys —");
    w("/// deserialize with SnakeCaseLower). Generated from the contract's");
    w("/// counter-name registry; nonzero values surface in the F12 panel.</summary>");
    w("public sealed class CountersData");
    w("{");
    for name in counters::COUNTER_NAMES {
        w(&format!(
            "    public ulong {} {{ get; set; }}",
            pascal(name)
        ));
    }
    w("}");
    w("");
    w("// ── Native PODs (LayoutKind.Explicit: offsets are the Rust offset_of!");
    w("// values; Size pins the total) — the structs NativeEngine marshals. ──");
    w("internal static partial class NativeEngine");
    w("{");
    {
        let s = size_of::<FmfQueryOptions>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal struct FmfQueryOptions");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public uint Sort;",
            offset_of!(FmfQueryOptions, sort)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint Desc;",
            offset_of!(FmfQueryOptions, desc)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint CaseMode;",
            offset_of!(FmfQueryOptions, case_mode)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint IncludeHiddenSystem;",
            offset_of!(FmfQueryOptions, include_hidden_system)
        ));
        w("    }");
    }
    w("");
    {
        let s = size_of::<FmfRow>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal struct FmfRow");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public ulong EntryRef;",
            offset_of!(FmfRow, entry_ref)
        ));
        w(&format!(
            "        [FieldOffset({})] public ulong Frn;",
            offset_of!(FmfRow, frn)
        ));
        w(&format!(
            "        [FieldOffset({})] public ulong Size;",
            offset_of!(FmfRow, size)
        ));
        w(&format!(
            "        [FieldOffset({})] public long Mtime;",
            offset_of!(FmfRow, mtime)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint NameOff;",
            offset_of!(FmfRow, name_off)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint ParentPathOff;",
            offset_of!(FmfRow, parent_path_off)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint Flags;",
            offset_of!(FmfRow, flags)
        ));
        w(&format!(
            "        [FieldOffset({})] public ushort NameLen;",
            offset_of!(FmfRow, name_len)
        ));
        w(&format!(
            "        [FieldOffset({})] public ushort ParentPathLen;",
            offset_of!(FmfRow, parent_path_len)
        ));
        w("    }");
    }
    w("");
    {
        let s = size_of::<FmfPage>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal struct FmfPage");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public uint RowCount;",
            offset_of!(FmfPage, row_count)
        ));
        w(&format!(
            "        [FieldOffset({})] public IntPtr Rows;",
            offset_of!(FmfPage, rows)
        ));
        w(&format!(
            "        [FieldOffset({})] public IntPtr Blob;",
            offset_of!(FmfPage, blob)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint BlobLen;",
            offset_of!(FmfPage, blob_len)
        ));
        w("    }");
    }
    w("");
    {
        let s = size_of::<FmfEvent>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal unsafe struct FmfEvent");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public uint Kind;",
            offset_of!(FmfEvent, kind)
        ));
        w(&format!(
            "        [FieldOffset({})] public ulong Entries;",
            offset_of!(FmfEvent, entries)
        ));
        w(&format!(
            "        [FieldOffset({})] public fixed byte Volume[16];",
            offset_of!(FmfEvent, volume)
        ));
        w("    }");
    }
    w("");
    {
        let s = size_of::<FmfVolumeStatus>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal unsafe struct FmfVolumeStatus");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public fixed byte Label[16];",
            offset_of!(FmfVolumeStatus, label)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint State;",
            offset_of!(FmfVolumeStatus, state)
        ));
        w(&format!(
            "        [FieldOffset({})] public ulong Entries;",
            offset_of!(FmfVolumeStatus, entries)
        ));
        w("    }");
    }
    w("");
    {
        let s = size_of::<FmfBlob>();
        w(&format!(
            "    [StructLayout(LayoutKind.Explicit, Size = {s})]"
        ));
        w("    internal struct FmfBlob");
        w("    {");
        w(&format!(
            "        [FieldOffset({})] public IntPtr Data;",
            offset_of!(FmfBlob, data)
        ));
        w(&format!(
            "        [FieldOffset({})] public uint Len;",
            offset_of!(FmfBlob, len)
        ));
        w("    }");
    }
    w("}");

    o
}

fn output_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("../../../app/FindMyFiles/Engine/Generated/EngineContract.g.cs")
}

/// Line-ending-insensitive comparison (git autocrlf may differ per clone).
fn normalize(s: &str) -> String {
    s.replace("\r\n", "\n")
}

fn main() {
    let rendered = render();
    let path = output_path();
    if std::env::args().any(|a| a == "--check") {
        let on_disk = std::fs::read_to_string(&path).unwrap_or_default();
        if normalize(&on_disk) != normalize(&rendered) {
            eprintln!(
                "EngineContract.g.cs drifted from fmf-contract — regenerate \
                 with `just contract-gen` and commit the result (ADR-0018)."
            );
            std::process::exit(1);
        }
        println!("EngineContract.g.cs is up to date");
        return;
    }
    std::fs::create_dir_all(path.parent().unwrap()).unwrap();
    std::fs::write(&path, rendered).unwrap();
    println!("wrote {}", path.display());
}
